func newDoctorCmd(flags *rootFlags) *cobra.Command {
	return &cobra.Command{
		Use:   "doctor",
		Short: "Check CLI health",
		RunE: func(cmd *cobra.Command, args []string) error {
			report := map[string]any{}

			// Check config
			cfg, err := config.Load(flags.configPath)
			if err != nil {
				report["config"] = fmt.Sprintf("error: %s", err)
			} else {
				report["config"] = "ok"
				report["config_path"] = cfg.Path
				report["base_url"] = cfg.BaseURL
			}

			// Check auth
			if cfg != nil {
				header := cfg.AuthHeader()
				if header == "" {
					report["auth"] = "not configured"
					report["auth_hint"] = "export HAPPENSTANCE_WEB_APP_COOKIE_AUTH=<your-key>"
				} else {
					report["auth"] = "configured"
					report["auth_source"] = cfg.AuthSource
				}
			}

			// Check auth environment variables
			authEnvChecked := 0
			authEnvSet := 0
			authEnvChecked++
			if os.Getenv("HAPPENSTANCE_WEB_APP_COOKIE_AUTH") != "" {
				authEnvSet++
			}
			if authEnvSet == 0 {
				report["env_vars"] = fmt.Sprintf("none set (checked %d)", authEnvChecked)
			} else {
				report["env_vars"] = fmt.Sprintf("%d/%d set", authEnvSet, authEnvChecked)
			}

			// Check API connectivity and validate credentials
			if cfg != nil && cfg.BaseURL != "" {
				httpClient := &http.Client{Timeout: 5 * time.Second}
				baseURL := strings.TrimRight(cfg.BaseURL, "/")

				// Step 1: Basic reachability (unauthenticated HEAD)
				headReq, _ := http.NewRequest("HEAD", baseURL, nil)
				headResp, headErr := httpClient.Do(headReq)
				apiReachable := false
				if headErr == nil {
					headResp.Body.Close()
					apiReachable = true
				}

				// If HEAD failed, try GET on common health endpoints
				if !apiReachable {
					for _, p := range []string{"/health", "/healthz", "/status", "/ping", ""} {
						healthResp, healthErr := httpClient.Get(baseURL + p)
						if healthErr != nil {
							continue
						}
						healthResp.Body.Close()
						apiReachable = true
						break
					}
				}

				if !apiReachable {
					report["api"] = fmt.Sprintf("unreachable: %s", headErr)
				} else {
					report["api"] = "reachable"
				}

				// Step 2: Validate credentials with an authenticated request
				authHeader := cfg.AuthHeader()
				if authHeader == "" {
					// No auth configured — skip credential validation
				} else if !apiReachable {
					report["credentials"] = "skipped (API unreachable)"
				} else {
					authReq, _ := http.NewRequest("GET", baseURL, nil)
					authReq.Header.Set("__session", authHeader)
					authReq.Header.Set("User-Agent", "contact-goat-pp-cli")
					authResp, authErr := httpClient.Do(authReq)
					if authErr != nil {
						report["credentials"] = "error: could not reach API"
					} else {
						authResp.Body.Close()
						switch {
						case authResp.StatusCode >= 200 && authResp.StatusCode < 300:
							report["credentials"] = "valid"
						case authResp.StatusCode == 401 || authResp.StatusCode == 403:
							report["credentials"] = fmt.Sprintf("invalid (HTTP %d) — check your credentials", authResp.StatusCode)
						default:
							// Non-auth HTTP error (404, 500, etc.) — don't blame credentials
							report["credentials"] = fmt.Sprintf("ok (HTTP %d from base URL, but auth was accepted)", authResp.StatusCode)
						}
					}
				}
			} else if cfg != nil && cfg.BaseURL == "" {
				report["api"] = "not configured (set base_url in config file)"
			}

			// Happenstance cookie-auth section
			checkHappenstance(report)
			checkHappenstanceGraphCoverage(flags, report)

			// LinkedIn MCP section (Python / uvx / profile)
			checkLinkedIn(report)

			// Deepline section (env var presence, dlp_ prefix, CLI on PATH)
			checkDeepline(report)

			// Happenstance public REST API (bearer surface). Adds three rows:
			// happenstance_api_key, happenstance_api_validity, happenstance_api_balance.
			// Probes are best-effort with a tight 5s context and never print
			// the full key value — only the recognized prefix + last 4 chars.
			checkHappenstanceAPI(cfg, report)

			report["version"] = version

			if flags.asJSON {
				return flags.printJSON(cmd, report)
			}

			// Human-readable output with color
			w := cmd.OutOrStdout()
			checkKeys := []struct{ key, label string }{
				{"config", "Config"},
				{"auth", "Auth"},
				{"api", "API"},
				{"credentials", "Credentials"},
				{"happenstance_cookies", "Happenstance: cookies"},
				{"happenstance_session", "Happenstance: session JWT"},
				{"happenstance_graph", "Happenstance: graph coverage"},
				{"linkedin_python", "LinkedIn: Python"},
				{"linkedin_uvx", "LinkedIn: uvx"},
				{"linkedin_binary", "LinkedIn: binary"},
				{"linkedin_profile", "LinkedIn: profile"},
				{"deepline_env", "Deepline: DEEPLINE_API_KEY"},
				{"deepline_prefix", "Deepline: key prefix"},
				{"deepline_cli", "Deepline: CLI on PATH"},
				{"happenstance_api_key", "Happenstance API: key"},
				{"happenstance_api_validity", "Happenstance API: validity"},
				{"happenstance_api_balance", "Happenstance API: balance"},
			}
			for _, ck := range checkKeys {
				v, ok := report[ck.key]
				if !ok {
					continue
				}
				s := fmt.Sprintf("%v", v)
				// Explicit-prefix path: new-style checks (Happenstance API,
				// future additions) emit values prefixed with "OK ", "WARN ",
				// or "FAIL " so the renderer never has to guess from
				// substrings. Strip the prefix before printing.
				var indicator string
				switch {
				case strings.HasPrefix(s, "OK "):
					indicator = green("OK")
					s = strings.TrimPrefix(s, "OK ")
				case strings.HasPrefix(s, "WARN "):
					indicator = yellow("WARN")
					s = strings.TrimPrefix(s, "WARN ")
				case strings.HasPrefix(s, "FAIL "):
					indicator = red("FAIL")
					s = strings.TrimPrefix(s, "FAIL ")
				default:
					// Legacy substring detection for older checks that have
					// not yet migrated to explicit prefixes.
					indicator = green("OK")
					if strings.Contains(s, "error") || strings.Contains(s, "not configured") || strings.Contains(s, "unreachable") || strings.Contains(s, "invalid") {
						indicator = red("FAIL")
					} else if strings.Contains(s, "not ") || strings.Contains(s, "skipped") || strings.Contains(s, "inferred") {
						indicator = yellow("WARN")
					}
				}
				fmt.Fprintf(w, "  %s %s: %s\n", indicator, ck.label, s)
			}
			// Print info keys without status indicator
			for _, key := range []string{"config_path", "base_url", "auth_source", "version"} {
				if v, ok := report[key]; ok {
					fmt.Fprintf(w, "  %s: %v\n", key, v)
				}
			}
			// Print auth setup hints (indented under Auth line)
			if hint, ok := report["auth_hint"]; ok {
				fmt.Fprintf(w, "  hint: %v\n", hint)
			}
			if hint, ok := report["happenstance_hint"]; ok {
				fmt.Fprintf(w, "  hint: %v\n", hint)
			}
			if hint, ok := report["deepline_hint"]; ok {
				fmt.Fprintf(w, "  hint: %v\n", hint)
			}
			return nil
		},
	}
}

// checkHappenstance populates doctor's Happenstance cookie-auth fields. We
// NEVER print the JWT, the cookie values, or anything beyond expiry status
// and cookie names.
func checkHappenstance(report map[string]any) {
	path, err := chromecookies.DefaultCookieFilePath(appConfigDir, "happenstance")
	if err != nil {
		report["happenstance_cookies"] = fmt.Sprintf("error: %s", err)
		return
	}
	cf, err := chromecookies.ReadCookieFile(path)
	if err != nil {
		if errors.Is(err, os.ErrNotExist) {
			report["happenstance_cookies"] = "not configured"
			report["happenstance_hint"] = "run: contact-goat-pp-cli auth login --chrome --service happenstance"
			return
		}
		report["happenstance_cookies"] = fmt.Sprintf("error: %s", err)
		return
	}
	report["happenstance_cookies"] = fmt.Sprintf("found: %d cookies (%s)", len(cf.Cookies), path)

	// Check __session JWT expiry without printing it.
	var jwt string
	for _, ck := range cf.Cookies {
		if ck.Name == "__session" {
			jwt = ck.Value
			break
		}
	}
	if jwt == "" {
		report["happenstance_session"] = "not found in cookie file (missing __session)"
		return
	}
	if client.IsJWTExpired(jwt) {
		report["happenstance_session"] = "expired or <10s from expiry (will refresh on next request)"
	} else {
		report["happenstance_session"] = "valid"
	}
}

// checkHappenstanceGraphCoverage hits /api/uploads/status/user to
// report how the user's synced data sources look. Surfaces when the
// LinkedIn CSV import last refreshed so users know the 1st-degree
// graph freshness and can re-upload if it is stale. Best-effort: any
// error here is non-fatal and produces a concise "status unknown" line.
func checkHappenstanceGraphCoverage(flags *rootFlags, report map[string]any) {
	if _, ok := report["happenstance_session"]; !ok {
		return // no cookies, skip
	}
	c, err := flags.newClientRequireCookies("happenstance")
	if err != nil {
		report["happenstance_graph"] = "unavailable (cookies not loaded)"
		return
	}
	// Refresh the session before making the authenticated call; doctor
	// is specifically the place people run to diagnose auth, so making
	// that refresh path exercised here is the point.
	if refErr := c.MaybeRefreshSession(); refErr != nil {
		report["happenstance_graph"] = fmt.Sprintf("session refresh failed: %s", trimErr(refErr.Error()))
		report["happenstance_session"] = fmt.Sprintf("expired; refresh FAILED: %s", trimErr(refErr.Error()))
		return
	}
	raw, err := c.Get("/api/uploads/status/user", nil)
	if err != nil {
		report["happenstance_graph"] = fmt.Sprintf("unavailable: %s", trimErr(err.Error()))
		return
	}
	if len(raw) == 0 {
		// Empty body on an authenticated endpoint is Clerk's
		// signed-out signal. It means the refresh above returned 200
		// but didn't actually hand us a fresh JWT — usually because
		// the source cookies are stale. Say so plainly; the previous
		// phrasing ("authenticated but …") was misleading.
		report["happenstance_graph"] = "signed-out (empty body on authenticated endpoint — session is dead, re-run `auth login --chrome` against a signed-in browser)"
		return
	}
	var resp struct {
		Statuses struct {
			LinkedInExt []struct {
				Status        string `json:"status"`
				IsActive      bool   `json:"isActive"`
				IsError       bool   `json:"isError"`
				LastRefreshed string `json:"last_refreshed"`
				Timestamp     string `json:"timestamp"`
			} `json:"linkedin_ext"`
		} `json:"statuses"`
		HasAnyUploads       bool `json:"hasAnyUploads"`
		ActiveAccountsCount int  `json:"activeAccountsCount"`
	}
	if err := jsonUnmarshal(raw, &resp); err != nil {
		report["happenstance_graph"] = fmt.Sprintf("decode failed: %s", trimErr(err.Error()))
		return
	}
	if len(resp.Statuses.LinkedInExt) == 0 {
		report["happenstance_graph"] = "no LinkedIn contacts synced yet (upload at happenstance.ai/integrations)"
		return
	}
	entry := resp.Statuses.LinkedInExt[0]
	age := ""
	freshness := graphFreshnessUnknown
	if ts, err := time.Parse(time.RFC3339, entry.LastRefreshed); err == nil {
		elapsed := time.Since(ts)
		age = fmt.Sprintf(" (%s ago)", humanAge(elapsed))
		freshness = classifyGraphFreshness(elapsed)
	}
	status := entry.Status
	if entry.IsError {
		status = "ERROR"
	}
	freshnessTag := ""
	switch freshness {
	case graphFreshnessStale:
		freshnessTag = " [STALE — re-upload at https://happenstance.ai/connections]"
	case graphFreshnessVeryStale:
		freshnessTag = " [VERY STALE — re-upload at https://happenstance.ai/connections]"
	}
	report["happenstance_graph"] = fmt.Sprintf("linkedin_ext: %s, last refreshed %s%s%s",
		status, fallbackStr(entry.LastRefreshed, "unknown"), age, freshnessTag)
	report["happenstance_graph_status"] = string(freshness)
}

// graphFreshness names the staleness bucket for the LinkedIn graph
// upload. Surfaced on the doctor JSON envelope as
// happenstance_graph_status so programmatic callers can react without
// parsing prose.
type graphFreshness string

const (
	graphFreshnessOK        graphFreshness = "ok"
	graphFreshnessStale     graphFreshness = "stale"
	graphFreshnessVeryStale graphFreshness = "very_stale"
	graphFreshnessUnknown   graphFreshness = "unknown"
)

// graphStaleThreshold and graphVeryStaleThreshold gate the doctor's
// stale-graph warning. 90/180 days are conservative defaults: the SF
// tasks that motivated U4 ran fine on a 9-month-old graph, so a 30-day
// trigger would have cried wolf on a working setup. 90 days catches
// degradation before the 180-day "you really need to re-upload" mark.
const (
	graphStaleThreshold     = 90 * 24 * time.Hour
	graphVeryStaleThreshold = 180 * 24 * time.Hour
)

// classifyGraphFreshness maps an elapsed-since-refresh duration to one
// of the freshness buckets used by checkHappenstanceGraphCoverage.
func classifyGraphFreshness(elapsed time.Duration) graphFreshness {
	switch {
	case elapsed >= graphVeryStaleThreshold:
		return graphFreshnessVeryStale
	case elapsed >= graphStaleThreshold:
		return graphFreshnessStale
	default:
		return graphFreshnessOK
	}
}

func trimErr(s string) string {
	if len(s) > 120 {
		return s[:120] + "..."
	}
	return s
}

func fallbackStr(s, def string) string {
	if strings.TrimSpace(s) == "" {
		return def
	}
	return s
}

func humanAge(d time.Duration) string {
	days := int(d.Hours() / 24)
	if days < 1 {
		h := int(d.Hours())
		if h < 1 {
			return fmt.Sprintf("%dm", int(d.Minutes()))
		}
		return fmt.Sprintf("%dh", h)
	}
	if days < 60 {
		return fmt.Sprintf("%dd", days)
	}
	months := days / 30
	return fmt.Sprintf("%dmo", months)
}

// jsonUnmarshal is a thin wrapper to keep the local helper name
// consistent with other check* helpers in this file.
func jsonUnmarshal(data []byte, v any) error {
	return json.Unmarshal(data, v)
}

// happenstanceAPIBaseURLOverride is an optional override for the bearer
// API base URL used by checkHappenstanceAPI. Tests set this to an
// httptest server URL so doctor never touches api.happenstance.ai.
// In production it stays empty and the client uses hpapi.DefaultBaseURL.
var happenstanceAPIBaseURLOverride string

// happenstanceAPIRecognizedPrefixes mirrors the loose prefix check in
// internal/config/happenstance_api.go. Doctor uses the same list so the
// "recognized prefix" verdict here matches the warning the config layer
// would emit if the key has a surprising shape.
var happenstanceAPIRecognizedPrefixes = []string{
	"hpn_live_personal_",
	"hpn_live_",
}

// checkHappenstanceAPI populates the three doctor rows for the
// Happenstance public REST API (bearer surface):
//
//   - happenstance_api_key       : presence + recognized-prefix check
//   - happenstance_api_validity  : GET /v1/users/me probe (only if key set)
//   - happenstance_api_balance   : GET /v1/usage probe (only if validity OK)
//
// Values are prefixed with "OK ", "WARN ", or "FAIL " so the display loop
// classifies them deterministically without substring matching.
//
// REDACTION: the full bearer key never reaches the report. The "key" row
// includes only the recognized prefix plus the last 4 characters of the
// key (e.g. "hpn_live_personal_...XXXX"). Validity probes go through the
// hpapi client whose error messages are already redacted.
//
// NETWORK: probes use a 5s context deadline so doctor never hangs on a
// slow upstream. Network errors degrade to WARN, not FAIL — the user may
// be offline and we should not block doctor on that.
//
// TODO: a fourth row, `happenstance_api_rotation`, was scoped in the plan
// but only if the key carries an embedded creation timestamp the OpenAPI
// docs describe. They do not, as of 2026-04-19, so the row is omitted.
// Slot it in here once a real key with a derivable date is in hand.
func checkHappenstanceAPI(cfg *config.Config, report map[string]any) {
	key := config.LoadAPIKey(cfg)
	if key == "" {
		report["happenstance_api_key"] = "WARN not set (cookie path may suffice; export HAPPENSTANCE_API_KEY=hpn_live_personal_... to enable the bearer surface)"
		// No key — skip validity and balance probes entirely. The two
		// rows are not added to the report so the display loop simply
		// does not render them.
		return
	}

	// Identify the prefix so we can render confirmation without leaking
	// the full literal. Unknown prefix is WARN, not FAIL: the call may
	// still succeed and future Happenstance surfaces (workspace keys,
	// etc.) should not break this check.
	prefix := ""
	for _, p := range happenstanceAPIRecognizedPrefixes {
		if strings.HasPrefix(key, p) {
			prefix = p
			break
		}
	}
	tail := keyTail(key)
	if prefix == "" {
		report["happenstance_api_key"] = fmt.Sprintf(
			"WARN configured but unknown prefix (...%s); recognized prefixes are %s",
			tail, strings.Join(happenstanceAPIRecognizedPrefixes, ", "),
		)
	} else {
		report["happenstance_api_key"] = fmt.Sprintf(
			"OK configured (%s...%s)", prefix, tail,
		)
	}

	// Validity probe. Tight 5s deadline so doctor stays snappy; network
	// errors degrade to WARN so we don't block the user offline.
	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()

	opts := []hpapi.Option{}
	if happenstanceAPIBaseURLOverride != "" {
		opts = append(opts, hpapi.WithBaseURL(happenstanceAPIBaseURLOverride))
	}
	c := hpapi.NewClient(key, opts...)

	user, err := c.Me(ctx)
	if err != nil {
		// Tease apart the failure modes the http layer reports. 401 is the
		// canonical "rotated/invalid key" path and gets a FAIL with the
		// rotation URL. Everything else (network, 5xx, malformed JSON)
		// degrades to WARN so a transient blip does not red-light doctor.
		emsg := err.Error()
		if strings.Contains(emsg, "401") {
			report["happenstance_api_validity"] = fmt.Sprintf(
				"FAIL 401 — key invalid or rotated. Rotate at %s",
				hpapi.RotationURL,
			)
			return
		}
		report["happenstance_api_validity"] = fmt.Sprintf(
			"WARN unreachable (%s)", trimErr(emsg),
		)
		return
	}
	if user.Email != "" {
		report["happenstance_api_validity"] = fmt.Sprintf("OK ok (user: %s)", user.Email)
	} else {
		report["happenstance_api_validity"] = "OK ok"
	}

	// Balance probe — only run when validity is OK. If has_credits is
	// false OR balance is 0, WARN with a top-up link. Network errors here
	// are WARN, not FAIL, for the same reason as validity above.
	usage, err := c.Usage(ctx)
	if err != nil {
		report["happenstance_api_balance"] = fmt.Sprintf(
			"WARN unreachable (%s)", trimErr(err.Error()),
		)
		return
	}
	if !usage.HasCredits || usage.BalanceCredits == 0 {
		report["happenstance_api_balance"] = fmt.Sprintf(
			"WARN %d credits — top up at https://happenstance.ai/settings/billing",
			usage.BalanceCredits,
		)
		return
	}
	report["happenstance_api_balance"] = fmt.Sprintf("OK %d credits", usage.BalanceCredits)
}

// keyTail returns the last 4 characters of a bearer key for confirmation
// rendering. Short keys (under 4 chars; should never happen in practice
// but tests sometimes pass odd inputs) are echoed verbatim without
// pretending to redact what is already short.
func keyTail(key string) string {
	if len(key) <= 4 {
		return key
	}
	return key[len(key)-4:]
}

// checkDeepline populates doctor's Deepline fields. We NEVER echo the API
// key value: only the source it came from ("flag" / "env" / "file:<path>" /
// "not found"), the prefix validity, and whether the official CLI is on
// PATH. The source attribution is what makes auto-discovery visible without
// trading off any secret-handling guarantees.
func checkDeepline(report map[string]any) {
	key, source, skips := resolveDeeplineKeyWithSkips("")
	if key == "" {
		report["deepline_env"] = "not set"
		report["deepline_hint"] = "export DEEPLINE_API_KEY=dlp_..., pass --deepline-key dlp_..., or run 'deepline auth status --reveal' if you've already authenticated with the Deepline CLI"
	} else {
		report["deepline_env"] = "set (" + source + ")"
		if strings.HasPrefix(key, "dlp_") {
			report["deepline_prefix"] = "ok (dlp_)"
		} else if strings.HasPrefix(key, "dpl_") {
			report["deepline_prefix"] = `invalid — "dpl_" is a Vercel prefix, not Deepline`
		} else {
			report["deepline_prefix"] = `invalid — Deepline keys start with "dlp_"`
		}
	}

	// Surface any sibling-CLI candidate files that were rejected during
	// discovery. This lets the user fix a mode-too-loose or wrong-prefix
	// problem without re-deriving the resolver's logic. Skips are paths +
	// reasons; never key values.
	if len(skips) > 0 {
		report["deepline_discovery_skipped"] = skips
	}

	// Informational: is the official CLI on PATH? Not required — we have
	// an HTTP fallback. When auto-discovery is in play (source starts with
	// "file:"), this also explains where the key came from at the file
	// system level for users tracing the trust chain.
	if path, err := exec.LookPath("deepline"); err == nil {
		report["deepline_cli"] = fmt.Sprintf("found: %s", path)
	} else {
		report["deepline_cli"] = "not found (HTTP fallback will be used)"
	}
}
